from django import forms
from catalog.models import Barco, Categoria, Puerto, Fabricante
from django.core.exceptions import ValidationError
from decimal import Decimal


class BarcoForm(forms.ModelForm):
    class Meta:
        model = Barco
        fields = ['nombre', 'categoria', 'puerto', 'fabricante', 'precio_dia', 'capacidad', 'imagen', 'descripcion', 'cantidad_disponible', 'activo']
        widgets = {
            'nombre': forms.TextInput(attrs={'class': 'form-control', 'placeholder': 'Nombre del barco'}),
            'categoria': forms.Select(attrs={'class': 'form-control'}),
            'puerto': forms.Select(attrs={'class': 'form-control'}),
            'fabricante': forms.Select(attrs={'class': 'form-control'}),
            'precio_dia': forms.NumberInput(attrs={'class': 'form-control', 'placeholder': 'Precio por día', 'step': '0.01'}),
            'capacidad': forms.NumberInput(attrs={'class': 'form-control', 'placeholder': 'Capacidad'}),
            'imagen': forms.FileInput(attrs={'class': 'form-control'}),
            'descripcion': forms.Textarea(attrs={'class': 'form-control', 'rows': 4, 'placeholder': 'Descripción del barco'}),
            'cantidad_disponible': forms.NumberInput(attrs={'class': 'form-control', 'placeholder': 'Cantidad disponible'}),
            'activo': forms.CheckboxInput(attrs={'class': 'form-check-input'}),
        }

    def clean_nombre(self):
        nombre = self.cleaned_data.get('nombre', '').strip()
        if not nombre:
            raise ValidationError('El nombre es obligatorio.')
        if len(nombre) < 3:
            raise ValidationError('El nombre debe tener al menos 3 caracteres.')
        return nombre

    def clean_precio_dia(self):
        precio = self.cleaned_data.get('precio_dia')
        if precio is not None and precio <= 0:
            raise ValidationError('El precio debe ser mayor a 0.')
        return precio

    def clean_capacidad(self):
        capacidad = self.cleaned_data.get('capacidad')
        if capacidad is not None and capacidad <= 0:
            raise ValidationError('La capacidad debe ser mayor a 0.')
        return capacidad

    def clean_cantidad_disponible(self):
        cantidad = self.cleaned_data.get('cantidad_disponible')
        if cantidad is not None and cantidad < 0:
            raise ValidationError('La cantidad no puede ser negativa.')
        return cantidad

