    estados_validos = dict(Reserva.ESTADO_CHOICES)

    if nuevo_estado not in estados_validos:
        messages.error(request, 'Estado inválido.')
        return redirect('admin_panel:reservation_detail', id=id)

    transiciones_validas = {
        'PENDIENTE_DE_PAGO': ['PAGADO', 'CANCELADA'],
        'PAGADO': ['EN_USO'],
        'EN_USO': ['DEVUELTO'],
        'DEVUELTO': [],
        'CANCELADA': [],
    }

    if nuevo_estado not in transiciones_validas.get(reserva.estado, []):
        messages.error(request, f'No se puede cambiar de {reserva.get_estado_display()} a {estados_validos[nuevo_estado]}.')
        return redirect('admin_panel:reservation_detail', id=id)

    reserva.estado = nuevo_estado
    reserva.save()
    messages.success(request, f'Estado de la reserva actualizado a {reserva.get_estado_display()}.')
    return redirect('admin_panel:reservation_detail', id=id)

from django.shortcuts import render, redirect, get_object_or_404
