@require_http_methods(["GET", "POST"])
def step1(request):
    """
    Paso 1 de la reserva: Confirmación de artículos.
    """
    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    if request.method == 'POST':
        request.session['reserva_datos'] = {
            'paso': 1,
            'fecha_creacion': datetime.now().isoformat(),
        }
        request.session.modified = True
        return redirect('reservations:step2')

    total = Decimal('0.00')
    for item in items:
        dias = (item.fecha_fin - item.fecha_inicio).days
        if dias < 1:
            dias = 1
        precio_base, tasa_combustible, item_total = calcular_precio_item(
            item.barco, item.cantidad, dias
        )
        item.precio_base = precio_base
        item.tasa_combustible = tasa_combustible
        item.subtotal = item_total
        total += item_total

    context = {
        'items': items,
        'total': total,
    }
    return render(request, 'reservations/step1.html', context)


@require_http_methods(["GET", "POST"])
def step2(request):
    """
    Paso 2 de la reserva: Datos del cliente.
    """
    if 'reserva_datos' not in request.session:
        messages.error(request, 'Debe completar el paso 1 primero.')
        return redirect('reservations:step1')

    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    if request.method == 'POST':
        form = ReservationStep2Form(request.POST)
        if form.is_valid():
            request.session['reserva_datos']['nombre'] = form.cleaned_data['nombre']
            request.session['reserva_datos']['email'] = form.cleaned_data['email']
            request.session['reserva_datos']['telefono'] = form.cleaned_data['telefono']
            request.session.modified = True
            return redirect('reservations:step3')
    else:
        form = ReservationStep2Form()

    usuario_nombre = ''
    usuario_email = ''
    if request.user.is_authenticated:
        usuario_nombre = request.user.get_full_name() or request.user.email
        usuario_email = request.user.email

    context = {
        'form': form,
        'usuario_nombre': usuario_nombre,
        'usuario_email': usuario_email,
    }
    return render(request, 'reservations/step2.html', context)


@require_http_methods(["GET", "POST"])
def step3(request):
    """
    Paso 3 de la reserva: Método de pago.
    """
    if 'reserva_datos' not in request.session or 'nombre' not in request.session.get('reserva_datos', {}):
        messages.error(request, 'Debe completar los pasos anteriores primero.')
        return redirect('reservations:step1')

    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    if request.method == 'POST':
        metodo_pago = request.POST.get('metodo_pago')

        if metodo_pago not in ['PAYPAL', 'CONTRA_REEMBOLSO']:
            messages.error(request, 'Método de pago inválido.')
        else:
            request.session['reserva_datos']['metodo_pago'] = metodo_pago
            request.session.modified = True
            return redirect('reservations:confirmation')

    context = {
        'metodos_pago': ['PAYPAL', 'CONTRA_REEMBOLSO'],
    }
    return render(request, 'reservations/step3.html', context)


@require_http_methods(["GET"])
def confirmation(request):
    """
    Confirmación de la reserva y creación en base de datos.
    """
    if 'reserva_datos' not in request.session or 'metodo_pago' not in request.session.get('reserva_datos', {}):
        messages.error(request, 'Debe completar todos los pasos primero.')
        return redirect('reservations:step1')

    cesta = get_or_create_cart(request)
    items = cesta.items.all()

    if not items.exists():
        messages.error(request, 'La cesta está vacía.')
        return redirect('reservations:cart')

    reserva_datos = request.session.get('reserva_datos', {})

    # Crear la reserva dentro de una transacción
    with transaction.atomic():
        codigo_seguimiento = str(uuid.uuid4())[:32]

        total = Decimal('0.00')
        importe_combustible_total = Decimal('0.00')
        fecha_inicio = None
        fecha_fin = None

        for item in items:
            dias = (item.fecha_fin - item.fecha_inicio).days
            if dias < 1:
                dias = 1
            precio_base, tasa_combustible, item_total = calcular_precio_item(
                item.barco, item.cantidad, dias
            )
            total += precio_base
            importe_combustible_total += tasa_combustible

            if not fecha_inicio or item.fecha_inicio < fecha_inicio:
                fecha_inicio = item.fecha_inicio
            if not fecha_fin or item.fecha_fin > fecha_fin:
                fecha_fin = item.fecha_fin

        importe_total = total + importe_combustible_total

        reserva = Reserva.objects.create(
            codigo_seguimiento=codigo_seguimiento,
            cliente=request.user if request.user.is_authenticated else None,
            nombre_cliente=reserva_datos.get('nombre', ''),
            email_cliente=reserva_datos.get('email', ''),
            telefono_cliente=reserva_datos.get('telefono', ''),
            estado='PENDIENTE_DE_PAGO',
            metodo_pago=reserva_datos.get('metodo_pago', ''),
            importe_total=importe_total,
            importe_combustible=importe_combustible_total,
            fecha_inicio=fecha_inicio,
            fecha_fin=fecha_fin,
        )

        for item in items:
            dias = (item.fecha_fin - item.fecha_inicio).days
            if dias < 1:
                dias = 1
            tasa_dia = calcular_tasa_combustible(item.barco, 1)

            ItemReserva.objects.create(
                reserva=reserva,
                barco=item.barco,
                cantidad=item.cantidad,
                precio_unitario=item.barco.precio_dia,
                tasa_combustible_dia=tasa_dia,
            )

        # Vaciar la cesta
        cesta.items.all().delete()

        # Enviar correo de confirmación
        enviar_confirmacion_reserva(reserva)

    # Limpiar sesión
    if 'reserva_datos' in request.session:
        del request.session['reserva_datos']
    request.session.modified = True

    context = {
        'reserva': reserva,
    }
    return render(request, 'reservations/confirmation.html', context)


@require_http_methods(["POST"])
def cancel_reservation(request, codigo):
    """
    Cancela una reserva si está en estado PENDIENTE_DE_PAGO.
    """
    reserva = get_object_or_404(Reserva, codigo_seguimiento=codigo)

    if reserva.estado == 'PENDIENTE_DE_PAGO':
        reserva.delete()
        messages.success(request, 'Reserva cancelada correctamente.')
    else:
        messages.error(request, 'No se puede cancelar una reserva que no está pendiente de pago.')

    return redirect('tracking:detail', codigo=codigo)

